#include <stdio.h>
#include <stdlib.h>

int count = 0;

void backtrack(int* a, int* p, int n, int k, int i, int prev) {
    if (i == n) {
        int cnt = 0;
        for (int j = 1; j < n; j++) {
            if (p[j] > p[j-1]) cnt++;
        }
        if (cnt == k) count++;
        return;
    }
    if (a[i] != 0) {
        p[i] = a[i];
        backtrack(a, p, n, k, i+1, p[i]);
    } else {
        for (int j = 1; j <= n; j++) {
            int found = 0;
            for (int l = 0; l < i; l++) {
                if (p[l] == j) {
                    found = 1;
                    break;
                }
            }
            if (!found) {
                p[i] = j;
                backtrack(a, p, n, k, i+1, p[i]);
                p[i] = 0;
            }
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int* a = (int*) malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        int* p = (int*) malloc(n * sizeof(int));
        count = 0;
        backtrack(a, p, n, k, 0, -1);
        printf("%d\n", count);
        free(a);
        free(p);
    }
    return 0;
}

